import React, { useMemo } from 'react';
import { Line } from 'react-konva';

const PenTool = ({ points, strokeWidth = 2, stroke = '#000000' }) => {
  // Advanced smoothing using quadratic Bezier curves
  const smoothPoints = useMemo(() => {
    if (points.length < 6) return points;

    const smoothed = [];
    smoothed.push(points[0], points[1]); // First point

    // Process points in groups of 4 (2 coordinate pairs)
    for (let i = 2; i < points.length - 2; i += 2) {
      const prevX = points[i - 2];
      const prevY = points[i - 1];
      const currX = points[i];
      const currY = points[i + 1];
      const nextX = points[i + 2] || currX;
      const nextY = points[i + 3] || currY;

      // Calculate control points for smoother curves
      const cp1x = prevX + (currX - prevX) * 0.8;
      const cp1y = prevY + (currY - prevY) * 0.8;
      const cp2x = currX + (nextX - currX) * 0.2;
      const cp2y = currY + (nextY - currY) * 0.2;

      // Add interpolated points for smooth curves
      for (let t = 0; t <= 1; t += 0.2) {
        const x = Math.pow(1 - t, 2) * currX + 
                  2 * (1 - t) * t * cp1x + 
                  Math.pow(t, 2) * cp2x;
        const y = Math.pow(1 - t, 2) * currY + 
                  2 * (1 - t) * t * cp1y + 
                  Math.pow(t, 2) * cp2y;

        smoothed.push(x, y);
      }
    }

    // Add last point
    if (points.length >= 2) {
      smoothed.push(points[points.length - 2], points[points.length - 1]);
    }

    return smoothed;
  }, [points]);

  return (
    <Line
      points={smoothPoints}
      stroke={stroke}
      strokeWidth={strokeWidth}
      tension={0.3}
      lineCap="round"
      lineJoin="round"
      globalCompositeOperation="source-over"
      perfectDrawEnabled={false}
      shadowForStrokeEnabled={false}
      hitStrokeWidth={0}
      listening={false}
    />
  );
};

export default React.memo(PenTool);
